settings.cus_css:
.rto-re-registration .image-text-heading{margin:0 !important ;}
.rto-re-registration.image_text_section .image-text-block{align-items: center;}

.rto-re-registration .image_text_right h2{color:#fff;}

.rto-re-registration.image_text_section .image-text-heading{max-width:100%;}

.rto-re-registration.image_text_section .image-text-description{font-size: 16px;line-height: 22px;}

@media screen and (max-width:575px){
.rto-re-registration.image_text_section .image-text-description{font-size: 14px;}
}

.rto-re-registration.image_text_section .image_text_right{font-size: 16px;line-height: 22px;}

@media screen and (max-width:575px){
.rto-re-registration.image_text_section .image_text_right{font-size: 14px;}
}

.rto-re-registration-second{padding-top:0;}
.rto-re-registration-second .image_text_right{width:100%;}
.rto-re-registration-second .image_text_right a{color:inherit;text-decoration:underline}
.image_text_right ul{margin-bottom:35px;}

.rto-re-registration-second .image_text_right a:hover{color:inherit;}

.rto-re-registration-second.image_text_section .image_text_right{font-size: 16px;line-height: 22px;}

.rto-re-registration-second.image_text_section .image_text_right ul li:after{top:7px;}

@media screen and (max-width:575px){
.rto-re-registration-second.image_text_section .image_text_right{font-size: 14px;}
}
